INSERT INTO `tblannouncements` (`announcementid`, `name`, `message`, `showtousers`, `showtostaff`, `showname`, `dateadded`, `userid`) VALUES
(1, '📢 Important Announcement: Missing Checkouts', '<p>Team,<br>I&#8217;ve noticed that some checkouts are missing from the CRM. Please remember that accurate check-in and checkout data is essential &#8212; especially when calculating salaries.</p>\n<p>&#9989; <strong>Going forward, make sure to always complete your check-out at the end of the day.</strong></p>\n<p>This is a serious matter, and missing entries can affect your salary calculation. Let\'s stay disciplined and consistent with our daily updates.</p>\n<p>Thank you for your cooperation.</p>', 0, 1, 0, '2025-05-30 11:04:29', 'Ashikh Rahiman  M ');
