INSERT INTO `tblcontracts` (`id`, `content`, `description`, `subject`, `client`, `datestart`, `dateend`, `contract_type`, `project_id`, `addedfrom`, `dateadded`, `isexpirynotified`, `contract_value`, `trash`, `not_visible_to_client`, `hash`, `signed`, `signature`, `marked_as_signed`, `acceptance_firstname`, `acceptance_lastname`, `acceptance_email`, `acceptance_date`, `acceptance_ip`, `short_link`, `last_sent_at`, `contacts_sent_to`, `last_sign_reminder_at`) VALUES
(1, '<h2 style=\"text-align:center;\"><span style=\"text-decoration:underline;\"><strong>Website Development Agreement</strong></span></h2>\n<p style=\"text-align:center;\"><strong>This Agreement</strong> is entered into on 24-May-2025 between <span style=\"color:rgb(224,62,45);\"><strong>Ziron Media FZ LLC</strong></span>, hereinafter referred to as the &#8220;Developer,&#8221; and <span style=\"color:rgb(224,62,45);\"><strong>Piptan Group</strong></span>, hereinafter referred to as the &#8220;Client.&#8221;</p>\n<p></p>\n<p></p>\n<h3>1. <strong>Project Overview</strong></h3>\n<p>The Developer agrees to design and develop a custom real estate website for the Client. This website will be built using Next.js and will include a content management system (CMS) that allows the Client to manage property listings, agents, media, and customer inquiries. The website will be responsive, SEO-friendly, and designed for performance and scalability.</p>\n<hr>\n<h3>2. <strong>Scope of Work</strong></h3>\n<p>The Developer will provide the following services:</p>\n<ul>\n<li>\n<p>Custom user interface (UI) and user experience (UX) design tailored to the Client&#8217;s branding and target audience.</p>\n</li>\n<li>\n<p>Frontend development using Next.js, ensuring fast loading speeds, modern design practices, and SEO optimization.</p>\n</li>\n<li>\n<p>A complete property listing module with filters, search functions, and detail pages for each listing.</p>\n</li>\n<li>\n<p>An admin dashboard integrated with a custom CMS to manage listings, agents, images, content, and inquiries.</p>\n</li>\n<li>\n<p>Media gallery support for property photos and videos.</p>\n</li>\n<li>\n<p>Contact and inquiry forms linked to the Client&#8217;s email or CRM system.</p>\n</li>\n<li>\n<p>Blog/news module (optional, if required).</p>\n</li>\n<li>\n<p>Basic SEO setup including meta tags, image alt text, and sitemap.</p>\n</li>\n<li>\n<p>Assistance with deployment to a hosting platform of the Client&#8217;s choice.</p>\n</li>\n<li>\n<p>A 30-day post-launch support period for bug fixes and minor assistance.</p>\n</li>\n</ul>\n<p><em>Note: Hosting and domain purchase are not included in this agreement. However, the Developer will provide full support for deployment on the Client&#8217;s selected hosting provider (such as Vercel, AWS, or shared hosting).</em></p>\n<hr>\n<h3>3. <strong>Timeline</strong></h3>\n<p>The estimated project duration is 7 to 10 Days , starting from the date the initial payment is received and all required content is provided. This includes time for design, development, testing, and revisions.</p>\n<hr>\n<h3>4. <strong>Payment Terms</strong></h3>\n<p>The total cost for the project is AED 3,000. This will be paid in two phases:</p>\n<ul>\n<li>\n<p>50% advance payment (AED 1,500) to initiate the project.</p>\n</li>\n<li>\n<p>50% balance payment (AED 1,500) before deployment and handover.</p>\n</li>\n</ul>\n<p>All payments will be made via bank transfer or other mutually agreed methods. Work will not proceed to the next stage without the respective milestone payment.</p>\n<p>Optional add-ons are available upon request, such as a blog/news module (AED 500) or WhatsApp chat and Google Analytics integration (AED 300).</p>\n<hr>\n<h3>5. <strong>Revisions</strong></h3>\n<p>The Developer will provide up to two rounds of design and functionality revisions as part of this agreement. Any additional revisions or change requests outside the original scope will be charged separately at a rate of AED 150 per hour.</p>\n<hr>\n<h3>6. <strong>Post-Launch Support and Maintenance</strong></h3>\n<p>The Developer will provide 30 days of free support following the official launch date. This support includes bug fixes, technical assistance, and small adjustments.</p>\n<p>After the 30-day period, optional maintenance packages are available:</p>\n<ul>\n<li>\n<p>Technical maintenance: AED 300 per month</p>\n</li>\n<li>\n<p>CMS content updates (up to 5 edits/month): AED 250 per month</p>\n</li>\n<li>\n<p>SEO monitoring and reports: AED 400 per month</p>\n</li>\n</ul>\n<p>Maintenance contracts are not included in this agreement and can be signed separately.</p>\n<hr>\n<h3>7. <strong>Ownership and Intellectual Property</strong></h3>\n<p>Once full payment is made, the Client will receive complete ownership of the website, including source code, designs, and content. The Developer retains the right to display the project in their portfolio unless otherwise agreed in writing.</p>\n<hr>\n<h3>8. <strong>Confidentiality</strong></h3>\n<p>Both parties agree to keep all confidential business and technical information exchanged during the project strictly confidential and not disclose it to any third parties without prior written consent.</p>\n<hr>\n<h3>9. <strong>Termination Clause</strong></h3>\n<p>Either party may terminate this agreement with written notice. In case of termination, the Client will pay the Developer for work completed up to that point based on the stage of development.</p>\n<hr>\n<h3>10. <strong>Limitation of Liability</strong></h3>\n<p>The Developer shall not be held responsible for third-party failures, such as hosting server downtime, domain issues, or email service interruptions. The Developer&#8217;s liability is limited to the value of the contract.</p>\n<hr>\n<h3>11. <strong>Governing Law</strong></h3>\n<p>This agreement shall be governed and interpreted in accordance with the laws of the United Arab Emirates.</p>', '', 'Website Development Contract – Real Estate CMS for Piptan Group', 2, '2025-05-26', '2025-06-02', 1, 9, 1, '2025-05-24 19:18:10', 0, 3000.00, 0, 0, 'b8aaa278bf182f1f5538ad1c18effb6f', 1, 'signature.png', 0, 'Anshuman', 'Wellington', 'anshuman@piptan.com', '2025-05-27 17:19:19', '42.104.236.19', NULL, NULL, NULL, NULL),
(2, '<p style=\"text-align:center;\"><span style=\"text-decoration:underline;\"><span style=\"font-size:12pt;color:rgb(224,62,45);\"><strong><img src=\"https://crm.zironmedia.com/media/public/ziron-logo-dark.svg\" width=\"204\" height=\"60\" alt=\"\" style=\"float:left;\"></strong></span></span></p>\n<p style=\"text-align:center;\"><span style=\"text-decoration:underline;\"><span style=\"font-size:12pt;color:rgb(224,62,45);\"><strong></strong></span></span></p>\n<p style=\"text-align:center;\"><span style=\"text-decoration:underline;\"><span style=\"font-size:12pt;color:rgb(224,62,45);\"><strong>WEBSITE DEVELOPMENT AGREEMENT</strong></span></span></p>\n<p style=\"text-align:center;\"><strong>This Agreement is made on 31-Jul- 2025 between:</strong></p>\n<p style=\"text-align:center;\"><span><strong>Ziron Media FZ LLC</strong></span><span>, a company registered in Dubai, United Arab Emirates, having its principal place of business at Dubai (hereinafter referred to as the \"Developer\"),</span></p>\n<p style=\"text-align:center;\"><span>AND</span></p>\n<p style=\"text-align:center;\"><span><strong>VEGAS PROPERTIES LLC</strong></span><span>, a company registered under license number 1181948 (hereinafter referred to as the \"Client\").</span></p>\n<p style=\"text-align:center;\"><span>This Agreement outlines the terms and conditions under which the Developer will design, develop, and deliver a custom real estate website with a content management system (CMS), as described below.</span></p>\n<p><span></span></p>\n<p><strong>1. PROJECT OVERVIEW</strong></p>\n<p><span>The Developer agrees to design and develop a fully responsive, SEO-friendly real estate website using modern technologies. The website will include property listing capabilities, an admin dashboard, a custom CMS, lead capture forms, and deployment support.</span></p>\n<div><hr></div>\n<p><span><strong>2. SCOPE OF WORK</strong></span></p>\n<ul>\n<li>\n<p><span>UI/UX Design (Custom modern design tailored for real estate)</span></p>\n</li>\n<li>\n<p><span>Frontend Development using Next.js</span></p>\n</li>\n<li>\n<p><span>Backend Development using Express.js</span></p>\n</li>\n<li>\n<p><span>Property Listings Module (searchable and filterable)</span></p>\n</li>\n<li>\n<p><span>CMS Integration (to manage properties, agents, content)</span></p>\n</li>\n<li>\n<p><span>Admin Dashboard (with login and content controls)</span></p>\n</li>\n<li>\n<p><span>Lead Capture &amp; Contact Forms</span></p>\n</li>\n<li>\n<p><span>Deployment Assistance</span></p>\n</li>\n<li>\n<p><span>30-Day Post-Launch Support and CMS Training</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>3. TECHNOLOGIES TO BE USED</strong></span></p>\n<ul>\n<li>\n<p><span>Frontend: Next.js</span></p>\n</li>\n<li>\n<p><span>Backend: Express.js</span></p>\n</li>\n<li>\n<p><span>Database: MongoDB or equivalent</span></p>\n</li>\n<li>\n<p><span>Hosting: Client&#8217;s own server &#160;(deployment assistance provided)</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>4. TIMELINE</strong></span></p>\n<p><span>The project will be delivered within 4&#8211;5 weeks from the date of receipt of the advance payment and required content from the Client.</span></p>\n<div><hr></div>\n<p><span><strong>5. PRICING &amp; PAYMENT TERMS</strong></span></p>\n<p><span><strong>Total Project Cost:</strong></span><span> AED 3885 (after discount)</span></p>\n<p><span><strong>Payment Schedule:</strong></span></p>\n<ul>\n<li>\n<p><span>50% Advance: AED 1942.50 (Due before project start)</span></p>\n</li>\n<li>\n<p><span>50% Final Payment: AED 1,942.50 (Due upon completion, before deployment)</span></p>\n</li>\n</ul>\n<p><span>Payment shall be made via bank transfer to the Developer&#8217;s official business account.</span></p>\n<div><hr></div>\n<p><span><strong>6. OPTIONAL ANNUAL MAINTENANCE CONTRACT (AMC)</strong></span></p>\n<p><span>An optional AMC is available at 15% of the total project cost (AED 582/year), which includes:</span></p>\n<ul>\n<li>\n<p><span>Monthly security checks</span></p>\n</li>\n<li>\n<p><span>Minor bug fixes</span></p>\n</li>\n<li>\n<p><span>Basic content updates (up to 2 hours/month)</span></p>\n</li>\n<li>\n<p><span>Data backup and uptime support</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>7. CLIENT RESPONSIBILITIES</strong></span></p>\n<p><span>The Client shall:</span></p>\n<ul>\n<li>\n<p><span>Provide timely access to logos, content, property details, and other materials</span></p>\n</li>\n<li>\n<p><span>Provide domain and hosting credentials if deployment is required</span></p>\n</li>\n<li>\n<p><span>Review and provide feedback within 2 business days of submissions</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>8. REVISIONS</strong></span></p>\n<ul>\n<li>\n<p><span>2 rounds of revisions included per phase (design/development)</span></p>\n</li>\n<li>\n<p><span>Additional revisions will be billed at AED 100/hour</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>9. INTELLECTUAL PROPERTY &amp; RIGHTS</strong></span></p>\n<ul>\n<li>\n<p><span>All deliverables become the Client&#8217;s property upon full payment</span></p>\n</li>\n<li>\n<p><span>The Developer retains the right to showcase the project in portfolios unless requested otherwise</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>10. WARRANTY &amp; SUPPORT</strong></span></p>\n<ul>\n<li>\n<p><span>30 days post-launch support for bug fixes and CMS usage assistance</span></p>\n</li>\n<li>\n<p><span>Major feature additions or redesigns are not included and will be quoted separately</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>11. TERMINATION CLAUSE</strong></span></p>\n<p><span>Either party may terminate the agreement with written notice. If terminated:</span></p>\n<ul>\n<li>\n<p><span>Work completed will be invoiced</span></p>\n</li>\n<li>\n<p><span>Advance payment is non-refundable</span></p>\n</li>\n<li>\n<p><span>Project delays of more than 30 days by the Client may result in suspension</span></p>\n</li>\n</ul>\n<div><hr></div>\n<p><span><strong>12. CONFIDENTIALITY</strong></span></p>\n<p><span>Both parties agree to keep all proprietary information, access credentials, and project materials confidential.</span></p>\n<div><hr></div>\n<p><span><strong>13. GOVERNING LAW</strong></span></p>\n<p><span>This Agreement shall be governed by the laws of the United Arab Emirates. Any disputes shall be resolved under UAE jurisdiction.</span></p>\n<div><hr></div>', 'This contract outlines the terms and conditions for the design, development, and deployment of a custom real estate website for VEGAS PROPERTIES LLC. The project includes UI/UX design, frontend development using Next.js, backend development using Express.js, CMS integration, property listings module, lead capture forms, deployment assistance, and 30-day post-launch support.\r\n\r\nThe contract also details payment terms, timeline, client responsibilities, and optional annual maintenance services. Hosting and domain registration are not included and remain the client’s responsibility.\r\n\r\nBy signing this contract, both parties agree to the scope, pricing, and conditions necessary to successfully complete and launch the website project.', 'Service Agreement – Real Estate Website for VEGAS PROPERTIES LLC', 12, '2025-08-01', '2025-08-31', 1, 13, 1, '2025-07-15 17:00:30', 0, 3885.00, 0, 0, '9c1c2ee5aa75231f98608a0e699381c9', 1, 'signature.png', 0, 'Anwar', 'Sajith', 'anwar.hsbc@gmail.com', '2025-07-31 15:50:25', '86.98.59.206', NULL, NULL, NULL, NULL),
(3, '<p style=\"text-align:center;\"><strong><img src=\"https://crm.zironmedia.com/media/public/ftyfyt.png\" width=\"757\" height=\"137\" alt=\"\"></strong></p>\n<p style=\"text-align:center;\"><strong></strong></p>\n<p style=\"text-align:center;\"><strong>This Service Agreement (&#8220;Agreement&#8221;)</strong> is made on 18th Sep 2025. between:</p>\n<p style=\"text-align:center;\"><strong>Client:</strong><br>Sphere IT Consultants DWC LLC<br>Principal Place of Business: Business Center Logistics City, Dubai Aviation City, Dubai, UAE</p>\n<p style=\"text-align:center;\"><strong>Agency:</strong><br>Ziron Media FZ LLC<br>Principal Place of Business: Moosa Tower 2, Sheikh Zayed Road, Dubai, UAE</p>\n<p style=\"text-align:center;\">(&#8220;Parties&#8221;)</p>\n<p style=\"text-align:center;\"></p>\n<hr>\n<h4></h4>\n<h4>1. Scope of Services</h4>\n<p>Ziron Media agrees to provide:</p>\n<ul>\n<li>\n<p>Brand Guidelines &amp; Design Language</p>\n</li>\n<li>\n<p>Custom Website Revamp (15&#8211;18 pages, Next.js with CMS &amp; responsive design)</p>\n</li>\n<li>\n<p>Marketing Collateral &amp; Brand Assets (digital + print)</p>\n</li>\n<li>\n<p>Keyword Research &amp; SEO Alignment (1-month monitoring included)</p>\n</li>\n</ul>\n<hr>\n<h4>2. Project Timeline</h4>\n<ul>\n<li>\n<p>Website frontend live <strong>on or before 5th October 2025</strong>.</p>\n</li>\n<li>\n<p>CMS integration completed within <strong>1 week</strong> after frontend launch.</p>\n</li>\n<li>\n<p>Branding, collateral, and SEO delivered in parallel with website development.</p>\n</li>\n</ul>\n<hr>\n<h4>3. Payment Terms</h4>\n<ul>\n<li>\n<p>50% advance upon signing this agreement.</p>\n</li>\n<li>\n<p>30% upon approval of website design &amp; brand guidelines.</p>\n</li>\n<li>\n<p>20% upon final delivery and handover.</p>\n</li>\n</ul>\n<hr>\n<h4>4. Deliverables Included</h4>\n<ul>\n<li>\n<p>Editable brand guideline files</p>\n</li>\n<li>\n<p>Fully developed Next.js website (18 pages max)</p>\n</li>\n<li>\n<p>Print &amp; digital collateral files</p>\n</li>\n<li>\n<p>SEO setup &amp; one-month reporting</p>\n</li>\n</ul>\n<hr>\n<h4>5. Exclusions</h4>\n<ul>\n<li>\n<p>Domain registration, hosting, or third-party software fees</p>\n</li>\n<li>\n<p>Content creation beyond placeholders (copywriting, photo, video)</p>\n</li>\n<li>\n<p>SEO beyond 1 month post-launch</p>\n</li>\n<li>\n<p>Post-project maintenance (available separately via AMC &#8211; AED 4,000/year)</p>\n</li>\n</ul>\n<hr>\n<h4>6. Intellectual Property</h4>\n<p>All final deliverables will become the property of Sphere IT upon full and final payment.</p>\n<hr>\n<h4>7. Confidentiality</h4>\n<p>Both parties agree to maintain confidentiality as per the NDA signed on 16th Sep 2025.</p>\n<hr>\n<h4>8. Termination</h4>\n<p>Either party may terminate with written notice. Client will be invoiced for completed work up to termination date.</p>\n<hr>\n<h4>9. Governing Law</h4>\n<p>This Agreement shall be governed by the laws of the UAE. Disputes resolved through arbitration in Dubai, UAE, in English.</p>\n<hr>\n<p></p>\n<p></p>', 'This Service Agreement covers the brand guidelines, custom website revamp (15–18 pages, Next.js with CMS & responsive design), marketing collateral, and SEO alignment for Sphere IT Consultants DWC LLC. The project includes deliverables such as editable brand guideline files, a fully developed website, print and digital collateral, and SEO setup with one-month monitoring. Payment milestones: 50% advance, 30% after design approval, and 20% upon final delivery. Exclusions include domain, hosting, additional content creation, and post-project maintenance (AMC available separately). Agreement governed under UAE law with arbitration in Dubai.', 'Service Agreement – Ziron Media & Sphere IT', 16, '2025-09-17', '2025-10-17', 0, 0, 1, '2025-09-17 20:24:55', 0, 35000.00, 0, 0, 'ef8692c90f9e996af5897c316aca9d30', 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(4, '<p style=\"text-align:center;\"><span style=\"font-size:18pt;color:rgb(224,62,45);\"><sup><strong>Digital Marketing &amp; Website Management Agreement</strong></sup></span></p>\n<p style=\"text-align:center;\"><span></span></p>\n<p style=\"text-align:center;\"><strong>This Agreement is made and entered into on 12-11-2025 between:</strong></p>\n<p style=\"text-align:center;\"><span style=\"font-size:12pt;\"><strong>Ziron Media FZ LLC</strong></span></p>\n<p style=\"text-align:center;\"><strong>Office: Dubai, UAE</strong></p>\n<p style=\"text-align:center;\"><strong>Represented by: Mr. Ashikh A., Managing Director</strong></p>\n<p style=\"text-align:center;\"><strong>(hereinafter referred to as the &#8220;Service Provider&#8221;)</strong></p>\n<p style=\"text-align:center;\"><strong>AND</strong></p>\n<p style=\"text-align:center;\"><strong><span style=\"font-size:12pt;\">Piptan</span> <span style=\"font-size:12pt;\">Capital</span> LLC</strong></p>\n<p style=\"text-align:center;\"><strong>Represented by: Mr. Shashi Piptan</strong></p>\n<p style=\"text-align:center;\"><strong>Website: <a href=\"https://piptan.ae\">piptan.ae</a></strong></p>\n<p style=\"text-align:center;\"><strong>(hereinafter referred to as the &#8220;Client&#8221;)</strong></p>\n<p style=\"text-align:center;\"><strong></strong></p>\n<p style=\"text-align:center;\"><strong>Collectively referred to as the &#8220;Parties.&#8221;</strong></p>\n<p><span></span></p>\n<p><span></span></p>\n<h2><span style=\"font-size:12pt;\"><strong>1. Scope of Services</strong></span></h2>\n<p><span>Ziron Media FZ LLC agrees to provide the following </span><span>monthly digital marketing and website management services</span><span> to Piptan Capital LLC:</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>SEO (6-month contract):</span><span> On-page and off-page optimization, keyword research, backlinks, and ranking performance reports.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Social Media Management:</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>8 Reels (client provides footage; shooting excluded)</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>12 Static Posts</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>6 Stories</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Caption writing, scheduling, and posting</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Website Management:</span><span> Regular content updates, minor design adjustments, and basic SEO maintenance.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Email Management:</span><span> Setup, organization, and technical support </span><span>(email marketing excluded)</span><span>.</span></p>\n<p></p>\n<p><span style=\"font-size:12pt;\"><strong>2. Additional Benefits</strong></span></p>\n<p><span>As part of this agreement, Ziron Media will provide the following value additions:</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Portfolio Website</span><span> &#8211; for </span><span>AED 400</span><span> only.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Company Profile Design</span><span> &#8211; worth </span><span>AED 1,500</span><span>, provided </span><span>FREE</span><span> </span><span>(printing charges apply)</span><span>.</span></p>\n<p><strong><span style=\"font-size:14pt;\">3. Account Management</span></strong></p>\n<p><span>A </span><span>dedicated Key Account Manager</span><span> will be assigned to Piptan Capital LLC to coordinate all digital activities, ensure timely execution, and share monthly performance updates.</span></p>\n<p><span style=\"font-size:14pt;\"><strong>4. Payment Terms</strong></span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>First 2 Months:</span><span> AED </span><span>3,000 per month</span><span> </span><span>(introductory offer)</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Payments are to be made </span><span>100% in advance at the start of each month</span><span>.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Invoice Payment Terms:</span><span> Payment due within </span><span>7 days</span><span> of invoice date.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Payment mode: Bank transfer or other mutually agreed methods.</span></p>\n<p><span style=\"font-size:14pt;\"><strong>5. Contract Duration</strong></span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>SEO Contract:</span><span> Minimum 6 months (renewable upon mutual consent).</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Digital Marketing:</span><span> Month-to-month basis.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Either party may terminate the agreement with </span><span>30 days written notice</span><span> after the minimum SEO term.</span></p>\n<p><span style=\"font-size:14pt;\"><strong>6. Exclusions</strong></span></p>\n<p><span>This agreement excludes:</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Paid advertising budgets (Meta, Google, or other ad platforms).</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>On-site videography or photography.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Major website redesign or new page development.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Email marketing campaigns (optional add-on).<br></span></p>\n<p><span style=\"font-size:14pt;\"><strong>7. Confidentiality</strong></span></p>\n<p><span>Both parties agree to maintain confidentiality regarding all information, data, and materials shared during and after the contract period.</span></p>\n<p><span style=\"font-size:14pt;\"><strong>8. Ownership &amp; Content Rights</strong></span></p>\n<p><span>All approved and fully paid deliverables (designs, content, and creatives) will remain the property of </span><span>Piptan Capital LLC</span><span>.</span></p>\n<p><span style=\"font-size:14pt;\"><strong>9. Limitation of Liability</strong></span></p>\n<p><span></span></p>\n<p><span>Ziron Media FZ LLC shall perform all services professionally and diligently. However, it shall not be liable for losses resulting from third-party platforms, algorithm changes, or factors beyond its control.</span><span></span><span></span></p>\n<p><span style=\"font-size:14pt;\"><strong>10. Acceptance &amp; Signatures</strong></span></p>\n<p><span>By signing this agreement, both parties acknowledge and agree to the terms stated above.</span><br><span></span></p>', '', 'SERVICE AGREEMENT ', 2, '2025-11-12', NULL, 0, 0, 1, '2025-11-12 12:32:07', 0, 3000.00, 0, 0, 'dc37b02947634154ccd87106fb78992c', 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
