(191, 10, 'proposal', 'Lead Capture System', 'QR registration form and lead database', 1.00, 5000.00, '', 1),
(192, 10, 'proposal', 'Touchscreen Game Development', 'Catch the Falling Products interactive game', 1.00, 11000.00, '', 2),
(193, 10, 'proposal', 'Email Automation Setup', 'Automated thank-you email system', 1.00, 2500.00, '', 3),
(194, 10, 'proposal', 'Admin Dashboard', 'Monitoring and data export dashboard', 1.00, 4000.00, '', 4),
(195, 10, 'proposal', 'System Integration & Testing', 'Deployment and testing', 1.00, 2500.00, '', 5),
(196, 5, 'estimate', 'Logo Redesign', 'Redesign of existing logo based on brand requirements. Includes concept refinement, revisions, and delivery of final logo in high-resolution formats (PNG, JPG, SVG, PDF) along with editable source files (AI/Vector) for web and print use.', 1.00, 800.00, '', 1),
(197, 47, 'invoice', 'Monthly Social Media Management (4 Brands)', 'Monthly social media content creation, management, and reporting for the following brands under Maxline LLC during the period of – 10 FEB  2025- 10 MARCH 2026', 1.00, 2500.00, '', 1),
(198, 47, 'invoice', 'Video shoot', 'Office/warehouse shoot for Commercial video', 1.00, 250.00, '', 2),
