INSERT INTO `tblprojectdiscussioncomments` (`id`, `discussion_id`, `discussion_type`, `parent`, `created`, `modified`, `content`, `staff_id`, `contact_id`, `fullname`, `file_name`, `file_mime_type`) VALUES
(1, 1, 'regular', NULL, '2025-05-12 13:16:22', NULL, '<p><strong>About the Book</strong></p>\n<ul>\n<li>Short description, synopsis, highlights.</li>\n</ul>\n<p><strong>About the Author</strong></p>\n<ul>\n<li>Author photo, short biography.</li>\n<li>Link to full \"About Author\" page.</li>\n</ul>\n<p data-start=\"648\" data-end=\"680\" class=\"\"><strong data-start=\"648\" data-end=\"678\">Pre-Order Benefits Section (if needed)</strong></p>\n<ul data-start=\"683\" data-end=\"731\">\n<li data-start=\"683\" data-end=\"731\" class=\"\">\n<p data-start=\"685\" data-end=\"731\" class=\"\">Early access, bonus content, signed copy, etc.</p>\n</li>\n</ul>\n<p data-start=\"842\" data-end=\"877\" class=\"\"><strong data-start=\"842\" data-end=\"875\">Testimonials or Early Reviews (if needed)</strong></p>', 2, 0, 'Melwin Af', NULL, NULL),
(2, 1, 'regular', NULL, '2025-05-12 13:17:14', NULL, '<p>ok ..i will update </p>', 1, 0, 'Ashikh Rahiman  M ', NULL, NULL),
(3, 1, 'regular', NULL, '2025-05-12 14:56:50', NULL, '<p>Introduction:</p>\n<p>The Urban Evolution of Dubai: A Blueprint for Infrastructure Investment* is a powerful and timely guide that unpacks how Dubai has transformed into one of the world’s most forward-thinking cities. Authored by Shashi Piptan— a Global Investment Advisor—the book explores the vision, planning, and execution behind Dubai’s meteoric rise.</p>\n<p>Blending deep research with practical insights, this book provides a clear lens into the city’s strategic infrastructure investments, urban planning models, and the regulatory frameworks that have attracted global investors. Whether you\'re a developer, investor, entrepreneur, or policymaker, you’ll gain a thorough understanding of how and where high returns can be realized in Dubai’s evolving landscape.</p>\n<p>With contributions from market experts, real estate professionals, and industry insiders, the book not only charts Dubai’s growth story but also offers a forward-looking perspective on where the next big opportunities lie.</p>\n<p>This is more than just a book—it’s a blueprint for those looking to align with Dubai’s future. If you want to understand what makes Dubai a global investment magnet, and how to capitalize on its ongoing transformation, this guide is your essential starting point.</p>\n<p></p>\n<p></p>\n<p>About the Author – Shashi Piptan</p>\n<p>Shashi Piptan is a seasoned Global Investment Advisor with a sharp focus on infrastructure development, real estate strategy, and international business growth. With over a decade of experience in corporate liaisoning and infrastructural negotiation, Shashi has successfully advised governments, multinational corporations, and private investors on high-stakes projects across the Middle East, Asia, and Europe.</p>\n<p>Known for his strategic insight and practical approach, Shashi specializes in identifying emerging opportunities in rapidly growing markets—particularly Dubai, where his work has contributed to unlocking high-return investments in real estate and urban development. His ability to bridge the gap between visionary planning and on-ground execution has made him a trusted name in the global investment community.</p>\n<p>Shashi’s deep understanding of market dynamics, regulatory frameworks, and future-ready infrastructure makes him uniquely positioned to guide investors through complex landscapes. His hands-on experience and expansive network enable him to create value-driven strategies that align with both commercial goals and long-term sustainability.</p>\n<p>As the author of The Urban Evolution of Dubai: A Blueprint for Infrastructure Investment, Shashi brings together his years of field expertise, offering readers an actionable roadmap to one of the world’s most dynamic investment destinations.</p>', 1, 0, 'Ashikh Rahiman  M ', NULL, NULL),
(4, 2, 'file', NULL, '2025-05-29 17:37:31', NULL, '<p>https://www.figma.com/proto/fBAySirNXisxRSd9Vw1ZS9/Piptan-Real-Estate?page-id=0%3A1&amp;node-id=1-2&amp;viewport=356%2C424%2C0.07&amp;t=4Lx0X12RNYznIxWP-1&amp;scaling=scale-down&amp;content-scaling=fixed&amp;starting-point-node-id=1%3A2</p>', 2, 0, 'Melwin Af', NULL, NULL);
