(9, 'Website Development  – Real Estate CMS for Piptan Group', '<p><a href=\"https://www.figma.com/proto/fBAySirNXisxRSd9Vw1ZS9/Piptan-Real-Estate?page-id=0%3A1&amp;node-id=1-2&amp;viewport=252%2C244%2C0.33&amp;t=RZTVgOJbd9llDsGl-1&amp;scaling=scale-down&amp;content-scaling=fixed&amp;starting-point-node-id=1%3A2\" target=\"_blank\" rel=\"noreferrer noopener\">Prototype Mockup &#8599;&#65039;</a></p>', 4, 2, 1, '2025-05-24', '2025-05-28', '2025-05-24', '2025-11-04 17:09:10', 0, 1, NULL, 0.00, NULL, 1, 1, 'a:0:{}'),
(10, 'Flyer Design – Abu Dhabi English Community Campaign', '<p><strong>&#128196; Project Description:</strong><br>Design and develop two attractive flyers aimed at promoting our services to the English-speaking community in Abu Dhabi. One flyer should target <strong>individual clients</strong> and the other should focus on <strong>corporate clients</strong>. The flyers must be visually appealing and clearly communicate our logistics and relocation services. Initial drafts to be reviewed before final confirmation.</p>\n<p><strong>Individual Services to Highlight:</strong></p>\n<ul>\n<li>\n<p>Domestic and International Relocations</p>\n</li>\n<li>\n<p>Packing and Moving</p>\n</li>\n<li>\n<p>Delivery to/from Worldwide</p>\n</li>\n<li>\n<p>Personalized Service</p>\n</li>\n<li>\n<p>Competitive Prices with High Quality</p>\n</li>\n<li>\n<p>Car Transportation to/from Around the World</p>\n</li>\n</ul>\n<p><strong>Corporate Services to Highlight:</strong></p>\n<ul>\n<li>\n<p>Domestic and International Cargo Movers</p>\n</li>\n<li>\n<p>Delivery to/from Worldwide</p>\n</li>\n<li>\n<p>Daily Express Service to GCC (Sea, Air &amp; Land)</p>\n</li>\n<li>\n<p>Packing and Lashing of Any Kind of Cargo</p>\n</li>\n<li>\n<p>Warehousing and Storage Facility</p>\n</li>\n<li>\n<p>Container / Ro-Ro and Break Bulk Services</p>\n</li>\n<li>\n<p>Customs Clearance and Customs Brokers</p>\n</li>\n<li>\n<p>3PL Services</p>\n</li>\n</ul>', 2, 1, 1, '2025-05-24', NULL, '2025-05-24', NULL, 100, 1, NULL, 0.00, NULL, 1, 1, 'a:0:{}'),
(12, 'BizDoctor Website Revamp – Business Consulting Platform for GCC & India', '<h2>&#127760; <strong>Project Overview:</strong></h2>\n<p>The goal is to <strong>revamp BizDoctor.me</strong> into a professional, dynamic, and scalable platform reflecting the company&#8217;s <strong>expansion into all GCC countries and India</strong>. The website will function as a <strong>consulting and training hub</strong>, covering a wide range of services such as <strong>taxation, company setup, business advisory, virtual CFO</strong>, training programs, online seminars, and <strong>consultation booking</strong>.</p>\n<hr>\n<h2>&#127919; <strong>Objectives:</strong></h2>\n<ul>\n<li>\n<p>Redesign the website to support <strong>multi-country, multilingual services</strong>.</p>\n</li>\n<li>\n<p>Offer detailed information on <strong>GCC and Indian taxation systems</strong>.</p>\n</li>\n<li>\n<p>Provide <strong>online consultation and training</strong> booking tools.</p>\n</li>\n<li>\n<p>Enable <strong>digital product offerings</strong> (e.g., seminars, guides, 1:1 training).</p>\n</li>\n<li>\n<p>Support <strong>SEO</strong> and <strong>content localization</strong> (English + Arabic optional).</p>\n</li>\n</ul>\n<p></p>\n<h2>&#129513; <strong>Expanded Services Section</strong></h2>\n<h3>&#9989; <strong>Services Offered</strong></h3>\n<h4>&#127462;&#127466;&#127480;&#127462;&#127478;&#127462;&#127476;&#127474;&#127463;&#127469;&#127472;&#127484; <strong>GCC Services</strong></h4>\n<ul>\n<li>\n<p><strong>Taxation &amp; Compliance</strong></p>\n<ul>\n<li>\n<p>UAE VAT Filing &amp; Registration</p>\n</li>\n<li>\n<p>Saudi Arabia VAT &amp; ZATCA Compliance</p>\n</li>\n<li>\n<p>Qatar VAT Advisory</p>\n</li>\n<li>\n<p>Oman VAT Services</p>\n</li>\n<li>\n<p>Bahrain VAT Filing</p>\n</li>\n<li>\n<p>Kuwait Tax Regulations</p>\n</li>\n<li>\n<p>GCC Corporate Tax Advisory</p>\n</li>\n<li>\n<p>Economic Substance Regulations (ESR)</p>\n</li>\n<li>\n<p>Anti-Money Laundering (AML) Advisory</p>\n</li>\n<li>\n<p>UAE Corporate Tax Filing</p>\n</li>\n<li>\n<p>Free Zone vs Mainland Tax Optimization</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Business Advisory</strong></p>\n<ul>\n<li>\n<p>Business Setup (UAE, KSA, Qatar, etc.)</p>\n</li>\n<li>\n<p>PRO Services &amp; Company Formation</p>\n</li>\n<li>\n<p>Virtual CFO Services</p>\n</li>\n<li>\n<p>Bookkeeping &amp; Accounting</p>\n</li>\n<li>\n<p>Payroll Management</p>\n</li>\n<li>\n<p>Financial Audit &amp; Due Diligence</p>\n</li>\n<li>\n<p>Business Valuation &amp; Forecasting</p>\n</li>\n<li>\n<p>Investment Advisory</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Financial Strategy</strong></p>\n<ul>\n<li>\n<p>Financial Planning &amp; Risk Management</p>\n</li>\n<li>\n<p>Capital Allocation</p>\n</li>\n<li>\n<p>Cost Reduction Strategies</p>\n</li>\n<li>\n<p>Cash Flow Optimization</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Supply Chain Management</strong></p>\n<ul>\n<li>\n<p>Procurement Advisory</p>\n</li>\n<li>\n<p>Vendor Management</p>\n</li>\n<li>\n<p>Inventory Optimization</p>\n</li>\n<li>\n<p>Logistics &amp; Distribution Planning</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Legal &amp; Compliance</strong></p>\n<ul>\n<li>\n<p>Corporate Law Advisory</p>\n</li>\n<li>\n<p>Contract Drafting &amp; Review</p>\n</li>\n<li>\n<p>Regulatory Compliance (GCC-specific)</p>\n</li>\n<li>\n<p>Labour Law Advisory</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Marketing Strategy</strong></p>\n<ul>\n<li>\n<p>Market Research &amp; Analysis</p>\n</li>\n<li>\n<p>Brand Positioning</p>\n</li>\n<li>\n<p>Digital Marketing Planning</p>\n</li>\n<li>\n<p>Campaign Management</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>IT Solutions &amp; Cybersecurity</strong></p>\n<ul>\n<li>\n<p>IT Infrastructure Setup</p>\n</li>\n<li>\n<p>Software &amp; Cloud Solutions</p>\n</li>\n<li>\n<p>Cybersecurity Risk Assessment</p>\n</li>\n<li>\n<p>Data Privacy &amp; Protection</p>\n</li>\n<li>\n<p>Security Audits &amp; Training</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Mental &amp; Physical Wellness Programs</strong></p>\n<ul>\n<li>\n<p>Stress Management Workshops</p>\n</li>\n<li>\n<p>Work-Life Balance Training</p>\n</li>\n<li>\n<p>Corporate Wellness Programs</p>\n</li>\n<li>\n<p>Mindfulness &amp; Resilience Coaching</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr>\n<h4>&#127470;&#127475; <strong>India Services</strong></h4>\n<ul>\n<li>\n<p><strong>Taxation &amp; Compliance</strong></p>\n<ul>\n<li>\n<p>GST Registration &amp; Filing</p>\n</li>\n<li>\n<p>Income Tax Returns (ITR)</p>\n</li>\n<li>\n<p>TDS Returns</p>\n</li>\n<li>\n<p>ROC Filing &amp; Compliance</p>\n</li>\n<li>\n<p>Company Incorporation (Pvt Ltd, LLP)</p>\n</li>\n<li>\n<p>Startup &amp; MSME Registration</p>\n</li>\n<li>\n<p>Digital Signature Certificates</p>\n</li>\n<li>\n<p>Tax Planning &amp; Assessment</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Finance &amp; Control</strong></p>\n<ul>\n<li>\n<p>Accounting &amp; Bookkeeping</p>\n</li>\n<li>\n<p>Virtual CFO Services</p>\n</li>\n<li>\n<p>Budgeting &amp; Forecasting</p>\n</li>\n<li>\n<p>Fundraising Advisory</p>\n</li>\n<li>\n<p>Money Control &amp; Expense Monitoring</p>\n</li>\n<li>\n<p>Internal Audit &amp; Process Improvement</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Financial Strategy</strong></p>\n<ul>\n<li>\n<p>Financial Risk Management</p>\n</li>\n<li>\n<p>Cost &amp; Profitability Analysis</p>\n</li>\n<li>\n<p>Investment Advisory</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Supply Chain Management</strong></p>\n<ul>\n<li>\n<p>Vendor Coordination</p>\n</li>\n<li>\n<p>Inventory &amp; Procurement Solutions</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Legal &amp; Compliance</strong></p>\n<ul>\n<li>\n<p>Company Law Advisory</p>\n</li>\n<li>\n<p>Contract Management</p>\n</li>\n<li>\n<p>Compliance Audits</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Marketing Strategy</strong></p>\n<ul>\n<li>\n<p>Digital &amp; Traditional Marketing</p>\n</li>\n<li>\n<p>Market Entry Strategy</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>IT Solutions &amp; Cybersecurity</strong></p>\n<ul>\n<li>\n<p>IT Consulting</p>\n</li>\n<li>\n<p>Cybersecurity Measures</p>\n</li>\n<li>\n<p>Data Protection Compliance</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Mental &amp; Physical Wellness Programs</strong></p>\n<ul>\n<li>\n<p>Employee Wellness Training</p>\n</li>\n<li>\n<p>Stress Management &amp; Mindfulness</p>\n</li>\n</ul>\n</li>\n</ul>\n<h3>&#127891; <strong>Training &amp; Development</strong></h3>\n<ul>\n<li>\n<p>Corporate Training Programs</p>\n</li>\n<li>\n<p>Webinars &amp; Virtual Workshops</p>\n</li>\n<li>\n<p>Certification Courses (Tax, Finance, Business)</p>\n</li>\n<li>\n<p>Company-Specific Training (GCC VAT, India GST, Corporate Tax)</p>\n</li>\n<li>\n<p>On-demand Video Courses (Coming Soon)</p>\n</li>\n</ul>\n<hr>\n<h3>&#128172; <strong>Consultation Booking Module</strong></h3>\n<ul>\n<li>\n<p>1-to-1 Consultation Booking (Zoom/Google Meet)</p>\n</li>\n<li>\n<p>Group Consultation Sessions</p>\n</li>\n<li>\n<p>Dynamic Calendar Integration</p>\n</li>\n<li>\n<p>Service-wise Payment Gateway Integration</p>\n</li>\n<li>\n<p>Automated Email/SMS Reminders</p>\n</li>\n</ul>', 4, 6, 1, '2025-05-27', '2025-06-07', '2025-05-27', '2025-11-04 17:09:40', 0, 1, NULL, 0.00, NULL, 1, 1, 'a:0:{}'),
