(15, 'Sphere IT – Brand Identity & Website Revamp', '<p>This project covers the complete refresh of Sphere IT&#8217;s brand identity and digital presence. The scope includes:</p>\n<ul>\n<li>\n<p>Creation of a refreshed <strong>brand identity system</strong>, including color palette, typography, logo refinements, design style guide, and tagline exploration.</p>\n</li>\n<li>\n<p>Delivery of a <strong>comprehensive brand kit</strong> with logo usage rules, patterns, and sample applications for internal and external use.</p>\n</li>\n<li>\n<p>Design and development of a <strong>modern, mobile-first website</strong> (15&#8211;18 pages) with CMS integration, SEO alignment, and responsive layouts.</p>\n</li>\n<li>\n<p>Creation of <strong>marketing collateral and brand assets</strong> such as business cards, letterheads, email signatures, editable company profile templates, social media post templates, and print-ready brochures/flyers.</p>\n</li>\n<li>\n<p><strong>Keyword research &amp; SEO alignment</strong>, covering on-page and technical SEO setup with monitoring and reporting.</p>\n</li>\n</ul>\n<p>The project will be executed in <strong>phases</strong> to ensure structured delivery, with regular updates and client approvals at each milestone.</p>', 2, 16, 1, '2025-09-26', '2025-10-31', '2025-09-26', NULL, 40, 1, NULL, 0.00, NULL, 1, 1, 'a:0:{}'),
(16, 'Interactive Lead Capture & Gamified Booth Activation', '', 2, 21, 1, '2026-03-05', NULL, '2026-03-05', NULL, 0, 1, NULL, 0.00, NULL, 1, 1, 'a:0:{}');
