INSERT INTO `tblproposals` (`id`, `subject`, `content`, `addedfrom`, `datecreated`, `total`, `subtotal`, `total_tax`, `adjustment`, `discount_percent`, `discount_total`, `discount_type`, `show_quantity_as`, `currency`, `open_till`, `date`, `rel_id`, `rel_type`, `assigned`, `hash`, `proposal_to`, `project_id`, `country`, `zip`, `state`, `city`, `address`, `email`, `phone`, `allow_comments`, `status`, `estimate_id`, `invoice_id`, `date_converted`, `pipeline_order`, `is_expiry_notified`, `acceptance_firstname`, `acceptance_lastname`, `acceptance_email`, `acceptance_date`, `acceptance_ip`, `signature`, `short_link`) VALUES
(1, 'Proposal for Custom Real Estate Website with CMS', '{proposal_items}', 1, '2025-05-24 10:44:16', 3000.00, 8150.00, 0.00, 0.00, 0.00, 5150.00, 'after_tax', 1, 3, '2025-05-31', '2025-05-24', 2, 'customer', 1, '0dc28df85f508169ca17b58266599ba1', 'Piptan Group ', 0, 234, '', 'Dubai', 'Dubai', 'Sheikh Zyed Road', 'anshuman@piptan.com', '+91 90231 35031', 1, 3, NULL, 11, NULL, 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(2, '📑 Digital Marketing Proposal- 🎁 Enjoy 40% OFF for the First 3 Months!', '{proposal_items}', 1, '2025-05-30 16:39:58', 1500.00, 2500.00, 0.00, 0.00, 40.00, 1000.00, 'after_tax', 1, 3, '2025-06-03', '2025-05-30', 1, 'lead', 1, '1421143096559ef214697f03acdba0de', 'Traveltalk Tourism LLC', NULL, 234, '0000000', 'Dubai ', ' Al Quoz 4 ', 'Al Quoz', 'Info@traveltalktourism.ae', '+971547127555', 1, 4, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(3, 'Proposal for Custom Real Estate Website with CMS', '{proposal_items}', 1, '2025-06-09 10:49:42', 3885.00, 8150.00, 0.00, 0.00, 0.00, 4265.00, 'after_tax', 1, 3, '2025-07-15', '2025-06-09', 2, 'lead', 1, '3a9d9e7a11c803bd237ba6ee4c2c6fb2', 'Vegas Properties ', 0, 234, '', 'Dubai', 'Al qouz ', 'Well Connected Business Centre', 'info@zironmedia.com', '', 1, 3, NULL, 18, NULL, 2, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(4, 'Website Development Proposal', '<h2><strong>1. Introduction</strong></h2>\n<p>Thank you for considering Ziron Media as your creative and digital partner. Based on your brief, we have carefully reviewed the requirements for brand guidelines, website revamp, marketing collateral, and SEO alignment.</p>\n<p>This financial proposal outlines the <strong>investment breakdown, descriptions of each service, and payment terms</strong> for the complete project.</p>\n<hr>\n<h2><strong>2. Project Cost (Item-Wise Pricing with Description)</strong></h2>\n<div class=\"_tableContainer_1rjym_1\">\n<div class=\"_tableWrapper_1rjym_13 group flex w-fit flex-col-reverse\">\n<table style=\"width:100%;height:272.961px;\">\n<thead>\n<tr style=\"height:44.7969px;\">\n<th style=\"width:16.9599%;height:44.7969px;\">Service Component</th>\n<th style=\"width:76.988%;height:44.7969px;\">Description</th>\n<th style=\"width:6.05208%;height:44.7969px;\">Amount (AED)</th>\n</tr>\n</thead>\n<tbody>\n<tr style=\"height:44.7969px;\">\n<td style=\"width:16.9599%;height:44.7969px;\"><strong>Brand Guidelines &amp; Design Language</strong></td>\n<td style=\"width:76.988%;height:44.7969px;\">Development of a refreshed brand identity system to ensure consistency across all touchpoints. Includes defining a color palette, typography rules, logo usage, and a design style guide. Sample applications (stationery, social media mockups) are included for practical reference.</td>\n<td style=\"width:6.05208%;height:44.7969px;\"><strong>7,000</strong></td>\n</tr>\n<tr style=\"height:67.1953px;\">\n<td style=\"width:16.9599%;height:67.1953px;\"><strong>Custom Website Revamp (15&#8211;18 Pages)</strong></td>\n<td style=\"width:76.988%;height:67.1953px;\">Complete <strong>custom Next.js website</strong> with modern, mobile-first design. Features include responsive layouts, CMS integration, SEO-friendly architecture, fast loading, and compatibility across all devices and browsers. Scope covers up to 18 pages, including corporate, service, and contact sections.</td>\n<td style=\"width:6.05208%;height:67.1953px;\"><strong>20,000</strong></td>\n</tr>\n<tr style=\"height:44.7969px;\">\n<td style=\"width:16.9599%;height:44.7969px;\"><strong>Marketing Collateral &amp; Brand Assets (Digital + Print)</strong></td>\n<td style=\"width:76.988%;height:44.7969px;\">Professional digital and print-ready assets, including business cards, letterheads, email signatures, editable company profile, 10&#8211;12 branded social media templates, and brochures/flyers. All materials aligned with the new design language.</td>\n<td style=\"width:6.05208%;height:44.7969px;\"><strong>6,000</strong></td>\n</tr>\n<tr style=\"height:0px;\">\n<td style=\"height:71.375px;width:16.9599%;\" rowspan=\"3\"><strong>Keyword Research &amp; SEO Alignment</strong></td>\n<td style=\"height:71.375px;width:76.988%;\" rowspan=\"3\">Comprehensive keyword research, on-page SEO optimization (meta tags, titles, descriptions), technical SEO setup (sitemap, schema, tracking), and 1-month monitoring/reporting to ensure SEO alignment.</td>\n<td style=\"height:71.375px;width:6.05208%;\" rowspan=\"3\"><strong>4,000</strong></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr>\n<h2><strong>3. Project Timeline &#8211; Website Delivery</strong></h2>\n<ul>\n<li>\n<p><strong>Website delivery date:</strong> <strong>October 5, 2025</strong></p>\n</li>\n<li>\n<p>Timeline assumes timely client feedback; delays may affect delivery schedule.</p>\n</li>\n<li>\n<p>All other services (brand guidelines, marketing collateral, SEO) will follow standard project milestones and will be coordinated alongside the website development.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>4. What&#8217;s Included</strong></h2>\n<ul>\n<li>\n<p>Full brand guidelines &amp; design language (colors, typography, logo rules).</p>\n</li>\n<li>\n<p>Custom Next.js website development with CMS, SEO setup, and up to 18 pages.</p>\n</li>\n<li>\n<p>Responsive design for mobile, tablet, and desktop.</p>\n</li>\n<li>\n<p>Marketing collateral: digital &amp; print-ready files (business cards, letterhead, company profile, social media templates, brochures).</p>\n</li>\n<li>\n<p>Keyword research and 1-month SEO alignment/monitoring.</p>\n</li>\n<li>\n<p>Regular updates and progress reviews during the project.</p>\n</li>\n<li>\n<p>Delivery of all editable source files for branding and collateral.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>5. What&#8217;s Not Included</strong></h2>\n<ul>\n<li>\n<p>Domain registration, web hosting, or third-party software subscriptions.</p>\n</li>\n<li>\n<p>Content creation (copywriting, photography, or video) beyond basic placeholders.</p>\n</li>\n<li>\n<p>Ongoing SEO or digital marketing beyond the 1-month post-launch monitoring.</p>\n</li>\n<li>\n<p>Maintenance or updates after project completion (can be quoted separately).</p>\n</li>\n</ul>\n<hr>\n<h2><strong>6. Payment Terms</strong></h2>\n<ul>\n<li>\n<p>50% advance upon project confirmation.</p>\n</li>\n<li>\n<p>30% upon approval of website design &amp; brand guidelines.</p>\n</li>\n<li>\n<p>20% upon final delivery &amp; handover.</p>\n</li>\n</ul>\n<p>Payments via bank transfer or company cheque. Bank details will be shared upon project confirmation.</p>\n<hr>\n<h2><strong>7. Optional Annual Maintenance Contract (AMC)</strong></h2>\n<p><strong>Basic AMC &#8211; AED 4000 /year</strong>:</p>\n<ul>\n<li>\n<p>Bug fixes and security updates</p>\n</li>\n<li>\n<p>Minor content updates (up to 5 changes per month)</p>\n</li>\n<li>\n<p>Regular website backups</p>\n</li>\n<li>\n<p>Minor design/layout updates</p>\n</li>\n</ul>\n<p><em>Note:</em> Major SEO campaigns, new pages, or advanced digital marketing beyond AMC scope will be quoted separately.</p>\n<hr>\n<h2><strong>8. Terms &amp; Conditions</strong></h2>\n<ul>\n<li>\n<p>Proposal validity: 30 days from the date of issue.</p>\n</li>\n<li>\n<p>Additional scope outside defined services will be quoted separately.</p>\n</li>\n<li>\n<p>Intellectual property rights for final deliverables are transferred to the client upon full payment.</p>\n</li>\n<li>\n<p>Ziron Media is not responsible for third-party software, hosting, or domain issues; associated costs are borne by the client.</p>\n</li>\n<li>\n<p>Confidentiality of client information is strictly maintained.</p>\n</li>\n<li>\n<p>Cancellation after project commencement may require payment for work completed.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>9. Closing Note</strong></h2>\n<p>We are confident that our approach will help strengthen Sphere IT&#8217;s brand presence, deliver a high-performance custom Next.js website by <strong>October 5, 2025</strong>, and create a scalable foundation for future growth.</p>\n<p>We welcome feedback or adjustments and will refine the proposal to suit your requirements.</p>\n<p></p>\n<h2><strong>10. </strong><strong>Project Cost</strong></h2>\n<p></p>\n<h3><span style=\"color:rgb(132,63,161);\">&#160;PROJECT OVERVIEW</span></h3>\n<p>We propose to design and develop a modern, professional website for your Document Clearing Services company. The site will be user-friendly, mobile-responsive, and built to support your business operations and lead generation, covering visa processing, PRO services, and business setup assistance.</p>\n<hr>\n<h3><span style=\"color:rgb(132,63,161);\">SITEMAP STRUCTURE (PAGES)</span></h3>\n<ol>\n<li>\n<p><strong>Home</strong></p>\n</li>\n<li>\n<p><strong>About Us</strong></p>\n</li>\n<li>\n<p><strong>Our Services</strong></p>\n<ul>\n<li>\n<p>Company Formation (Mainland / Freezone)</p>\n</li>\n<li>\n<p>Visa Services (Investor, Employment, Family)</p>\n</li>\n<li>\n<p>Emirates ID &amp; Medical Typing</p>\n</li>\n<li>\n<p>Attestation Services</p>\n</li>\n<li>\n<p>PRO Services</p>\n</li>\n<li>\n<p>Translation &amp; Legal Services</p>\n</li>\n<li>\n<p>Other Government Services</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Pricing / Packages</strong></p>\n</li>\n<li>\n<p><strong>FAQs</strong></p>\n</li>\n<li>\n<p><strong>Testimonials</strong></p>\n</li>\n<li>\n<p><strong>Blog / Articles</strong></p>\n</li>\n<li>\n<p><strong>Contact Us</strong></p>\n<ul>\n<li>\n<p>Inquiry Form</p>\n</li>\n<li>\n<p>Google Map</p>\n</li>\n<li>\n<p>WhatsApp Integration</p>\n</li>\n</ul>\n</li>\n</ol>\n<hr>\n<h3><span style=\"color:rgb(132,63,161);\">&#160;FUNCTIONALITY &amp; FEATURES</span></h3>\n<div class=\"_tableContainer_16hzy_1\">\n<div class=\"_tableWrapper_16hzy_14 group flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\" style=\"width:42.8367%;border-color:rgb(0,0,0);border-style:solid;\" border=\"1\">\n<thead>\n<tr>\n<th style=\"width:31.3758%;border-color:rgb(0,0,0);text-align:center;\"><span style=\"color:rgb(0,0,0);\"><strong>Feature</strong></span></th>\n<th style=\"width:68.6242%;border-color:rgb(0,0,0);text-align:center;\"><span style=\"color:rgb(0,0,0);\"><strong>Description</strong></span></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Fully Responsive</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Optimized for mobile, tablet, and desktop</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Easy Navigation</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Clear structure with service categorization</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Lead Forms</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Custom forms for service inquiries</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Click-to-Call &amp; WhatsApp</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Instant call and WhatsApp chat buttons</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Multi-language Ready</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Prepared for future Arabic/English content (Optional add-on)</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;SSL Security</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">HTTPS secure website</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;SEO-Ready</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Basic on-page SEO setup (titles, meta, keywords)</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Google Maps</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Location embedded in contact page</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Email Notifications</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">Automatic email alerts for form submissions</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Blog Integration</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">For company updates and SEO content</td>\n</tr>\n<tr>\n<td style=\"width:31.3758%;border-color:rgb(0,0,0);\">&#160;Admin Access</td>\n<td style=\"width:68.6242%;border-color:rgb(0,0,0);\">CMS for content updates (WordPress or Next.js Admin)</td>\n</tr>\n</tbody>\n</table>\n<div class=\"sticky end-(--thread-content-margin) h-0 self-end select-none\">\n<div class=\"absolute end-0 flex items-end\"><span></span></div>\n</div>\n</div>\n</div>\n<hr>\n<h3><span style=\"color:rgb(132,63,161);\">&#160;ADD-ONS (Optional)</span></h3>\n<div class=\"_tableContainer_16hzy_1\">\n<div class=\"_tableWrapper_16hzy_14 group flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Add-On</th>\n<th>Description</th>\n<th>Price</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Arabic Version</td>\n<td>Full RTL mirrored Arabic version</td>\n<td>+AED 750</td>\n</tr>\n<tr>\n<td>Content Writing</td>\n<td>Up to 8 pages professionally written</td>\n<td>+AED 500</td>\n</tr>\n<tr>\n<td>Monthly Maintenance</td>\n<td>Updates, backups, security checks</td>\n<td>+AED 150/month</td>\n</tr>\n<tr>\n<td>Google Ads Setup</td>\n<td>Campaign setup for leads</td>\n<td>Starting AED 750</td>\n</tr>\n</tbody>\n</table>\n<div class=\"sticky end-(--thread-content-margin) h-0 self-end select-none\">\n<div class=\"absolute end-0 flex items-end\"><span></span></div>\n</div>\n</div>\n</div>\n<hr>\n<h3>&#160;<span style=\"color:rgb(132,63,161);\">TIMELINE</span></h3>\n<div class=\"_tableContainer_16hzy_1\">\n<div class=\"_tableWrapper_16hzy_14 group flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Phase</th>\n<th>Duration</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Design Approval</td>\n<td>2&#8211;3 days</td>\n</tr>\n<tr>\n<td>Development</td>\n<td>5&#8211;7 working days</td>\n</tr>\n<tr>\n<td>Testing &amp; Handover</td>\n<td>1&#8211;2 days</td>\n</tr>\n</tbody>\n</table>\n<div class=\"sticky end-(--thread-content-margin) h-0 self-end select-none\">\n<div class=\"absolute end-0 flex items-end\"><span></span></div>\n</div>\n</div>\n</div>\n<p><strong>&#160;Total Time: 7&#8211;10 working days</strong></p>\n<hr>\n<h3><span style=\"color:rgb(132,63,161);\">&#160;NEXT STEPS</span></h3>\n<p>If approved, we will send you:</p>\n<ul>\n<li>\n<p>Proforma Invoice</p>\n</li>\n<li>\n<p>Website Requirement Sheet</p>\n</li>\n<li>\n<p>Access Requirements (Domain/Hosting or we can assist)</p>\n</li>\n</ul>\n<p></p>', 1, '2025-06-30 13:11:11', 1380.00, 3200.00, 0.00, 0.00, 0.00, 1820.00, 'after_tax', 1, 3, '2025-07-07', '2025-06-30', 4, 'customer', 1, '3826d626b755edb894d6438efa871cc9', 'PHENOM BUSINESS SOLUTIONS LLC', 0, 234, '', 'dubai', 'Nr GIGICO Metro', 'M03-13, Manazel Garhoud Building, Al Garhoud,', 'info@phenomuae.com', '+971 50 894 1483', 1, 4, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(5, 'Proposal for E-Commerce Website Development', '<p class=\"p1\"><span style=\"color:rgb(224,62,45);\"><strong><span class=\"s1\"><mark>Proposal for E-Commerce Website Development</mark></span></strong></span></p>\n<p class=\"p1\"><span class=\"s2\">Client: Three S Sports FZE LLC</span></p>\n<p class=\"p1\"><span class=\"s2\">Prepared by: Ziron Media FZ LLC</span></p>\n<p class=\"p1\"><span class=\"s2\">Date: 07-08-2025</span></p>\n<p class=\"p2\"><br><span class=\"s2\"></span></p>\n<p class=\"p1\"><strong><span class=\"s1\"><mark>Project Overview</mark></span></strong></p>\n<p class=\"p1\"><span class=\"s2\">Ziron Media is pleased to present this proposal to develop a complete e-commerce website for Three S Sports FZE LLC, a leading supplier of sports products in the UAE. The goal is to build a fully functional, high-performance online store to manage and sell over 500 sports-related products. The website will be built using Next.js with a customized backend CMS that allows full control over products, categories, orders, and content.</span></p>\n<p class=\"p1\"><strong><span class=\"s1\"><mark>Scope of Work</mark></span></strong></p>\n<p class=\"p1\"><span class=\"s3\"><mark>Frontend Development &#8211; Next.js</mark></span><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Developed using Next.js for high performance and SEO optimization</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Fully responsive design for mobile, tablet, and desktop</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Clean, modern UI/UX tailored for the sports industry</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Fast-loading pages and smooth user experience</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">SEO-ready structure for better visibility on search engines</span></li>\n</ul>\n<p class=\"p1\"><span class=\"s3\"><mark>Backend CMS</mark></span><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Secure admin login</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Product management (Add/Edit/Delete 500+ products)</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Manage categories and subcategories</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Inventory tracking</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Order management system</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Customer management</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Discount/coupon system</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Dashboard overview with analytics</span></li>\n</ul>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<p class=\"p1\"><span class=\"s1\"><mark>E-Commerce Functionalities</mark></span></p>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Shopping cart and wishlist</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">COD and online payment gateway integration (Stripe, PayTabs, Telr, etc.)</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Shipping method setup</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Invoice generation and email notifications</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Secure customer login and signup</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Product search and filters</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Order history for customers</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Product reviews and ratings</span></li>\n</ul>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<p class=\"p1\"><span class=\"s3\"><mark>Additional Features</mark></span></p>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">WhatsApp chat integration</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Blog or news module</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Newsletter subscription</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Social media links</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Related product recommendations</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Google Analytics and Facebook Pixel integration</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Multilingual support (optional)</span></li>\n</ul>\n<p class=\"p1\"><strong><span class=\"s3\"><mark>Content and Assets</mark></span></strong><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Product photos to be provided by the client</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Logo and branding elements to be provided</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Basic website content will be structured by Ziron Media with industry standards</span></li>\n</ul>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<p class=\"p1\"><strong><span class=\"s3\"><mark>Deliverables</mark></span></strong><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Complete responsive e-commerce website</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Custom backend CMS</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">SEO-friendly structure</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Admin panel training</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">1-month technical support post-launch</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Hosting and domain setup assistance if required</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Full source code and credentials handover after final payment</span></li>\n</ul>\n<p class=\"p2\"><span class=\"s2\"></span></p>\n<p class=\"p1\"><strong><span class=\"s1\"><mark>Timeline</mark></span></strong><span class=\"s2\"></span></p>\n<p class=\"p1\"><span class=\"s3\"><mark>Estimated Project Duration: 4 to 6 Weeks</mark></span><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Week 1: UI/UX mockups and approval</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Week 2&#8211;4: Frontend and backend development</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Week 5: Product upload and testing</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Week 6: Final review and deployment</span></li>\n</ul>\n<p class=\"p1\"><strong><span class=\"s1\"><mark>Payment Terms</mark></span></strong><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">50% Advance Payment (15,750 AED) &#8211; To initiate the project</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">50% Before Final Deployment (15,750 AED) &#8211; Before handover of live website and source code</span><span class=\"s2\"></span><span class=\"s2\"></span></li>\n</ul>\n<p><span style=\"background-color:rgb(255,241,0);\"><strong>Annual Maintenance Contract (AMC)</strong></span><span></span></p>\n<p><span>AMC: 15% of the Project Cost per Year<br>This includes:<br></span></p>\n<ul>\n<li><span>Technical support</span></li>\n<li><span>Minor content updates</span></li>\n<li><span>Plugin/library updates</span></li>\n<li><span>Website health monitoring</span></li>\n<li><span>Backup support</span></li>\n<li><span>Uptime monitoring</span><span></span></li>\n<li style=\"list-style-type:none;\"><span></span></li>\n<li style=\"list-style-type:none;\"><span>AMC does not include major redesigns or new feature development.</span></li>\n</ul>\n<p></p>\n<p class=\"p1\"><strong><span class=\"s1\"><mark>Terms and Conditions</mark></span></strong><span class=\"s2\"></span><span></span></p>\n<ol>\n<li><span>Project delivery depends on timely submission of content and approvals by the client</span></li>\n<li><span>Includes up to 2 rounds of design and content revisions</span></li>\n<li><span>Source code and backend access will be handed over only after full payment</span></li>\n<li><span>One-month free technical support after deployment</span></li>\n<li><span>AMC is optional and renewable annually</span></li>\n<li><span>All credentials and data shared during the project will remain confidential</span></li>\n<li><span>Third-party service charges (e.g., domain, hosting, payment gateway) are not included</span></li>\n</ol>\n<p class=\"p1\"><span class=\"s5\"><mark>Why Choose Ziron Media</mark></span><span class=\"s2\"></span></p>\n<ul class=\"ul1\">\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">UAE-based registered company with a strong development and design team</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Expertise in building scalable, high-performance websites</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Tailored solutions with a client-focused approach</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">End-to-end digital services including post-launch marketing, SEO, and ads</span></li>\n<li class=\"li1\"><span class=\"s4\"></span><span class=\"s2\">Experience in handling similar e-commerce projects locally and internationally</span></li>\n</ul>\n<p class=\"p1\"><span class=\"s5\"><mark>Next Steps</mark></span><span class=\"s2\"></span></p>\n<p class=\"p1\"><span class=\"s2\">Kindly confirm your approval to proceed with the project. We are ready to begin upon receipt of the advance payment and required materials.</span><span class=\"s2\"></span></p>\n<p class=\"p1\"><span class=\"s2\">Regards,</span></p>\n<p class=\"p1\"><span class=\"s6\"><b>Ashikh Rahiman</b></span></p>\n<p class=\"p1\"><span class=\"s6\">Founder &#8211; Ziron Media FZ LLC</span></p>\n<p class=\"p1\"><span class=\"s6\">Phone: +971 5666 46 539</span></p>\n<p class=\"p1\"><span class=\"s6\">Email: ashikh@zironmedia.com</span></p>\n<p class=\"p1\"><span class=\"s6\">Website: <a href=\"https://www.zironmedia.com\">www.zironmedia.com</a><br></span></p>\n<p class=\"p1\"><span class=\"s6\"><b>{proposal_items}</b></span></p>', 1, '2025-08-07 14:37:14', 31450.00, 31450.00, 0.00, 0.00, 0.00, 0.00, '', 1, 3, '2025-08-14', '2025-08-07', 15, 'customer', 1, 'c20d066673b9b6b62df73ef87e925ab7', 'Three S Sports FZE LLC', 0, 234, '', '', 'Dubai', 'Dubai', 'Info@3ssports.ae', '', 1, 4, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(6, 'Financial Proposal – Brand & Digital Refresh Project (Sphere IT)', '<h2><strong>1. Introduction</strong></h2>\n<p>Thank you for considering Ziron Media as your creative and digital partner. Based on your brief, we have carefully reviewed the requirements for brand guidelines, website revamp, marketing collateral, and SEO alignment.</p>\n<p>This financial proposal outlines the <strong>investment breakdown, descriptions of each service, and payment terms</strong> for the complete project.</p>\n<hr>\n<h2><strong>2. Project Cost (Item-Wise Pricing with Description)</strong></h2>\n<div class=\"_tableContainer_1rjym_1\">\n<div class=\"_tableWrapper_1rjym_13 group flex w-fit flex-col-reverse\">\n<table style=\"width:100%;height:272.961px;\">\n<thead>\n<tr style=\"height:44.7969px;\">\n<th style=\"width:16.9599%;height:44.7969px;\">Service Component</th>\n<th style=\"width:76.988%;height:44.7969px;\">Description</th>\n<th style=\"width:6.05208%;height:44.7969px;\">Amount (AED)</th>\n</tr>\n</thead>\n<tbody>\n<tr style=\"height:44.7969px;\">\n<td style=\"width:16.9599%;height:44.7969px;\"><strong>Brand Guidelines &amp; Design Language</strong></td>\n<td style=\"width:76.988%;height:44.7969px;\">Development of a refreshed brand identity system to ensure consistency across all touchpoints. Includes defining a color palette, typography rules, logo usage, and a design style guide. Sample applications (stationery, social media mockups) are included for practical reference.</td>\n<td style=\"width:6.05208%;height:44.7969px;\"><strong>7,000</strong></td>\n</tr>\n<tr style=\"height:67.1953px;\">\n<td style=\"width:16.9599%;height:67.1953px;\"><strong>Custom Website Revamp (15&#8211;18 Pages)</strong></td>\n<td style=\"width:76.988%;height:67.1953px;\">Complete <strong>custom Next.js website</strong> with modern, mobile-first design. Features include responsive layouts, CMS integration, SEO-friendly architecture, fast loading, and compatibility across all devices and browsers. Scope covers up to 18 pages, including corporate, service, and contact sections.</td>\n<td style=\"width:6.05208%;height:67.1953px;\"><strong>20,000</strong></td>\n</tr>\n<tr style=\"height:44.7969px;\">\n<td style=\"width:16.9599%;height:44.7969px;\"><strong>Marketing Collateral &amp; Brand Assets (Digital + Print)</strong></td>\n<td style=\"width:76.988%;height:44.7969px;\">Professional digital and print-ready assets, including business cards, letterheads, email signatures, editable company profile, 10&#8211;12 branded social media templates, and brochures/flyers. All materials aligned with the new design language.</td>\n<td style=\"width:6.05208%;height:44.7969px;\"><strong>6,000</strong></td>\n</tr>\n<tr style=\"height:0px;\">\n<td style=\"height:71.375px;width:16.9599%;\" rowspan=\"3\"><strong>Keyword Research &amp; SEO Alignment</strong></td>\n<td style=\"height:71.375px;width:76.988%;\" rowspan=\"3\">Comprehensive keyword research, on-page SEO optimization (meta tags, titles, descriptions), technical SEO setup (sitemap, schema, tracking), and 1-month monitoring/reporting to ensure SEO alignment.</td>\n<td style=\"height:71.375px;width:6.05208%;\" rowspan=\"3\"><strong>4,000</strong></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr>\n<h2><strong>3. Project Timeline &#8211; Website Delivery</strong></h2>\n<ul>\n<li>\n<p><strong>Website delivery date:</strong> <strong>October 5, 2025</strong></p>\n</li>\n<li>\n<p>Timeline assumes timely client feedback; delays may affect delivery schedule.</p>\n</li>\n<li>\n<p>All other services (brand guidelines, marketing collateral, SEO) will follow standard project milestones and will be coordinated alongside the website development.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>4. What&#8217;s Included</strong></h2>\n<ul>\n<li>\n<p>Full brand guidelines &amp; design language (colors, typography, logo rules).</p>\n</li>\n<li>\n<p>Custom Next.js website development with CMS, SEO setup, and up to 18 pages.</p>\n</li>\n<li>\n<p>Responsive design for mobile, tablet, and desktop.</p>\n</li>\n<li>\n<p>Marketing collateral: digital &amp; print-ready files (business cards, letterhead, company profile, social media templates, brochures).</p>\n</li>\n<li>\n<p>Keyword research and 1-month SEO alignment/monitoring.</p>\n</li>\n<li>\n<p>Regular updates and progress reviews during the project.</p>\n</li>\n<li>\n<p>Delivery of all editable source files for branding and collateral.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>5. What&#8217;s Not Included</strong></h2>\n<ul>\n<li>\n<p>Domain registration, web hosting, or third-party software subscriptions.</p>\n</li>\n<li>\n<p>Content creation (copywriting, photography, or video) beyond basic placeholders.</p>\n</li>\n<li>\n<p>Ongoing SEO or digital marketing beyond the 1-month post-launch monitoring.</p>\n</li>\n<li>\n<p>Maintenance or updates after project completion (can be quoted separately).</p>\n</li>\n</ul>\n<hr>\n<h2><strong>6. Payment Terms</strong></h2>\n<ul>\n<li>\n<p>50% advance upon project confirmation.</p>\n</li>\n<li>\n<p>30% upon approval of website design &amp; brand guidelines.</p>\n</li>\n<li>\n<p>20% upon final delivery &amp; handover.</p>\n</li>\n</ul>\n<p>Payments via bank transfer or company cheque. Bank details will be shared upon project confirmation.</p>\n<hr>\n<h2><strong>7. Optional Annual Maintenance Contract (AMC)</strong></h2>\n<p><strong>Basic AMC &#8211; AED 4000 /year</strong>:</p>\n<ul>\n<li>\n<p>Bug fixes and security updates</p>\n</li>\n<li>\n<p>Minor content updates (up to 5 changes per month)</p>\n</li>\n<li>\n<p>Regular website backups</p>\n</li>\n<li>\n<p>Minor design/layout updates</p>\n</li>\n</ul>\n<p><em>Note:</em> Major SEO campaigns, new pages, or advanced digital marketing beyond AMC scope will be quoted separately.</p>\n<hr>\n<h2><strong>8. Terms &amp; Conditions</strong></h2>\n<ul>\n<li>\n<p>Proposal validity: 30 days from the date of issue.</p>\n</li>\n<li>\n<p>Additional scope outside defined services will be quoted separately.</p>\n</li>\n<li>\n<p>Intellectual property rights for final deliverables are transferred to the client upon full payment.</p>\n</li>\n<li>\n<p>Ziron Media is not responsible for third-party software, hosting, or domain issues; associated costs are borne by the client.</p>\n</li>\n<li>\n<p>Confidentiality of client information is strictly maintained.</p>\n</li>\n<li>\n<p>Cancellation after project commencement may require payment for work completed.</p>\n</li>\n</ul>\n<hr>\n<h2><strong>9. Closing Note</strong></h2>\n<p>We are confident that our approach will help strengthen Sphere IT&#8217;s brand presence, deliver a high-performance custom Next.js website by <strong>October 5, 2025</strong>, and create a scalable foundation for future growth.</p>\n<p>We welcome feedback or adjustments and will refine the proposal to suit your requirements.</p>\n<p></p>\n<h2><strong>10. </strong><strong>Project Cost</strong></h2>\n<p>{proposal_items}</p>', 1, '2025-09-10 16:31:10', 35000.00, 37000.00, 0.00, 0.00, 0.00, 2000.00, 'after_tax', 1, 3, '2025-09-30', '2025-09-10', 3, 'lead', 1, 'a3b105d9b6b6ae635358449c9785985e', 'Sphere IT Consultants DWC LLC', NULL, 234, '390667', 'Dubai', 'Dubai World Central ', '', 'info@zironmedia.com', '', 1, 3, NULL, 26, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(7, 'Proposal for Landing Page Development – Ejari Assistance & Office Space Solutions', '<h2><strong>Introduction</strong></h2>\n<p>We appreciate the opportunity to assist [Client Name] in creating a <strong>high-performing landing page</strong> for your Ejari-related services.<br>The landing page will be designed to support your <strong>advertising campaigns</strong>, attract potential customers, and enable direct <strong>cost calculation &amp; online payments</strong>.</p>\n<p>Our focus is to deliver a landing page that is:<br>&#10004;&#65039; Modern, responsive, and mobile-friendly<br>&#10004;&#65039; Conversion-focused for ads<br>&#10004;&#65039; Automated with calculator &amp; payment integration</p>\n<hr>\n<h2><strong>Deliverables (Included)</strong></h2>\n<ol>\n<li>\n<p><strong>Landing Page Design &amp; Development</strong></p>\n<ul>\n<li>\n<p>Responsive design (desktop, tablet, mobile)</p>\n</li>\n<li>\n<p>Dedicated sections for Ejari Assistance, Virtual Ejari, and Office Space Rental</p>\n</li>\n<li>\n<p>SEO-ready structure optimized for advertising</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Dynamic Cost Calculator</strong></p>\n<ul>\n<li>\n<p>Real-time calculator for service pricing</p>\n</li>\n<li>\n<p>Easy-to-use interface with instant results</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Online Payment Integration</strong></p>\n<ul>\n<li>\n<p>Secure payment gateway setup (Stripe / PayTabs / PayPal / Local UAE Gateway)</p>\n</li>\n<li>\n<p>Success/failure pages with confirmation email/WhatsApp notification</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Lead Capture &amp; Tracking</strong></p>\n<ul>\n<li>\n<p>Contact form (with database storage)</p>\n</li>\n<li>\n<p>WhatsApp quick inquiry button</p>\n</li>\n<li>\n<p>Google Analytics &amp; Facebook Pixel integration</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Technical Setup &amp; Deployment</strong></p>\n<ul>\n<li>\n<p>Hosting and domain configuration (if required)</p>\n</li>\n<li>\n<p>SSL certificate setup for security</p>\n</li>\n<li>\n<p>Full deployment &amp; live testing</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Support &amp; Training</strong></p>\n<ul>\n<li>\n<p>Dashboard/management walkthrough</p>\n</li>\n<li>\n<p>1-month free technical support (bug fixing &amp; minor edits)</p>\n</li>\n</ul>\n</li>\n</ol>\n<hr>\n<h2><strong>Not Included (Optional Add-ons)</strong></h2>\n<p><br>&#10060; Stock images/videos (unless provided by client)<br>&#10060; SMS gateway integration (extra cost)<br>&#10060; Social Media Management or Paid Ads (separate service)<br>&#10060; Advanced multi-page website development (this proposal is for <strong>one landing page only</strong>)</p>\n<hr>\n<h2><strong>Annual Maintenance (Optional AMC)</strong></h2>\n<p>To ensure your landing page continues to perform well, we offer flexible maintenance packages:</p>\n<ul>\n<li>\n<p><strong>Standard AMC &#8211; AED 600 /year</strong></p>\n<ul>\n<li>\n<p>Quarterly website health &amp; security check</p>\n</li>\n<li>\n<p>Up to 6 minor edits per year</p>\n</li>\n<li>\n<p>Backup &amp; monitoring</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Premium AMC &#8211; AED 2.000 /year</strong></p>\n<ul>\n<li>\n<p>Everything in Standard</p>\n</li>\n<li>\n<p>Priority support (response within 24 hrs)</p>\n</li>\n<li>\n<p>Unlimited minor edits (text &amp; images)</p>\n</li>\n<li>\n<p>Annual performance &amp; SEO audit</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr>\n<h2><strong>Itemized Costing</strong></h2>\n<p><strong>{proposal_items}</strong></p>\n<p><strong>Payment Terms:</strong></p>\n<ul>\n<li>\n<p>50% upfront</p>\n</li>\n<li>\n<p>50% upon final delivery before handover</p>\n</li>\n</ul>\n<hr>\n<h2><strong>Timeline</strong></h2>\n<ul>\n<li>\n<p>Content Collection &amp; Kickoff: 2 days</p>\n</li>\n<li>\n<p>Design &amp; Development: 7&#8211;8 working days</p>\n</li>\n<li>\n<p>Testing &amp; Deployment: 2 days<br><strong>Total Delivery:</strong> 10 working days</p>\n</li>\n</ul>\n<hr>\n<h2><strong>Next Steps</strong></h2>\n<ol>\n<li>\n<p>Approve the proposal and confirm the scope</p>\n</li>\n<li>\n<p>Sign off with 50% upfront payment</p>\n</li>\n<li>\n<p>Ziron Media will begin design &amp; development immediately</p>\n</li>\n</ol>\n<p></p>', 1, '2025-09-16 14:17:50', 2950.00, 2950.00, 0.00, 0.00, 0.00, 0.00, '', 1, 3, '2025-09-23', '2025-09-16', 4, 'lead', 1, '2c7c72f5b08b939c7ce42fbd92c3355f', 'Xavier Business Centre ', NULL, 234, '', ' ', 'dubai', 'Dubai', 'info@zironmedia.com', '', 1, 4, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(8, ' Digital Marketing & Website Management Proposal', '<p style=\"text-align:center;\"><span style=\"color:rgb(224,62,45);font-size:14pt;\"><strong>Digital Marketing &amp; Website Management Proposal</strong></span></p>\n<p><span></span></p>\n<p><span></span></p>\n<p><span>Client: Piptan</span></p>\n<p><span>Website: <a href=\"https://piptan.ae/\">piptan.ae</a></span></p>\n<p><span>Prepared by: Ziron Media FZ LLC</span></p>\n<p><span></span></p>\n<p><span><b><i>Overview</i></b></span><span></span></p>\n<p><span>Ziron Media FZ LLC proposes a complete digital marketing, SEO, and website management package designed to strengthen Piptan&#8217;s online presence and business growth.</span><span></span></p>\n<p><span>Our team will handle the full digital ecosystem &#8212; including SEO, social media management, creative content, and website maintenance &#8212; ensuring the brand maintains consistent visibility, engagement, and conversion-focused communication across all platforms.</span><span></span></p>\n<p><span>With a 6-month SEO contract, our goal is to deliver measurable improvements in search rankings, organic traffic, and overall brand reach, supported by monthly performance reports and strategy reviews.</span><span></span></p>\n<p><span><b><i>Objectives</i></b></span><span></span></p>\n<ul>\n<li><span>Improve Google ranking and increase organic website traffic.</span></li>\n<li><span>Build a strong and consistent social media presence.</span></li>\n<li><span>Maintain and update the website for better performance and user experience.</span></li>\n<li><span>Manage official emails effectively for smooth business communication.</span></li>\n<li><span>Ensure ongoing digital support and performance tracking.</span><span></span></li>\n</ul>\n<p><span></span></p>\n<p><span style=\"color:rgb(22,145,121);\"><b><i>Scope of Work</i></b></span><span></span></p>\n<p><span><b><i>1. SEO (Search Engine Optimization) &#8212; 6-Month Contract</i></b></span><span></span></p>\n<ul>\n<li><span>Complete on-page and off-page optimization.</span></li>\n<li><span>Keyword research, meta tag setup, and backlink building.</span></li>\n<li><span>Technical SEO checks (site speed, mobile optimization, etc.).</span></li>\n<li><span>Monthly SEO performance reports and ranking updates.</span></li>\n<li><span>Content optimization for better search visibility.</span></li>\n</ul>\n<p><span>(Initial SEO contract period: 6 months, renewable upon review.)</span><span></span></p>\n<p><span><b><i>2. Social Media Management</i></b></span><span></span></p>\n<ul>\n<li><span>Platforms: Instagram, Facebook, and LinkedIn (if applicable).</span></li>\n<li><span>Monthly content plan and posting schedule.</span></li>\n<li><span>Content Plan (Per Month):<br></span>\n<ul>\n<li><span>8 Reels (shooting not included; client provides footage)</span></li>\n<li><span>12 Static Posts (designed by Ziron Media)</span></li>\n<li><span>6 Stories</span></li>\n</ul>\n</li>\n<li><span></span></li>\n<li><span>Caption writing, hashtags, and engagement management.</span></li>\n<li><span>Monthly performance insights and report.</span></li>\n</ul>\n<p><span><b><i>3. Website Management</i></b></span><span></span></p>\n<ul>\n<li><span>Regular content updates (text, banners, and images).</span></li>\n<li><span>Minor design improvements and maintenance.</span></li>\n<li><span>SEO performance checks and basic technical support.</span></li>\n<li><span>Ensuring smooth functionality and updated visuals.</span></li>\n</ul>\n<p><span><b><i>4. Email Management</i></b></span><span></span></p>\n<ul>\n<li><span>Email account setup, configuration, and maintenance.</span></li>\n<li><span>Inbox organization and technical support.</span></li>\n<li><span>Basic troubleshooting for business emails.</span></li>\n<li><span>(Email marketing campaigns are excluded and can be quoted separately.)</span></li>\n</ul>\n<p><span></span></p>\n<p><span style=\"color:rgb(224,62,45);\"><b><i><u>Exclusions</u></i></b></span></p>\n<ul>\n<li><span>Video shooting or on-site content creation.</span></li>\n<li><span>Paid ad budgets (Meta, Google, or others).</span></li>\n<li><span>Advanced website redesign or new module development.</span></li>\n<li><span>Email marketing campaigns (optional add-on).</span><span></span></li>\n</ul>\n<p><span><b><i>Payment and Terms</i></b></span></p>\n<p><span><b><i>{proposal_items}</i></b></span></p>\n<p></p>\n<ul>\n<li><span>First 2 Months: AED 3,000/month (introductory offer)</span></li>\n</ul>\n<p><span></span><span>&#160;</span><span>(exclusive of ad spend and video shooting)</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Payment:</span><span> 100% monthly in advance.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Contract Duration:</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Digital Marketing:</span><span> Month-to-Month</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>SEO:</span><span> 6-Month Minimum Contract</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Invoice Terms:</span><span> Payment due within 7 days of invoice date.</span><span></span></p>\n<p><span></span></p>\n<p><span><b>Why Choose Ziron Media</b></span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Experienced team in </span><span>SEO, digital marketing, and website development</span><span>.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Data-driven approach</span><span> with monthly reports and transparent results.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span></span><span>Dedicated account management</span><span> for smooth coordination.</span></p>\n<p><span><span class=\"Apple-tab-span\"> </span>&#8226;<span class=\"Apple-tab-span\"> </span>Quick response and ongoing support via WhatsApp, call, or email.</span></p>\n<p><span></span></p>\n<p><span><b>Prepared by:</b></span></p>\n<p><span>Ashikh A.</span></p>\n<p><span>Managing Director &#8211; Ziron Media FZ LLC</span></p>\n<p><span>info@zironmedia.com | <a href=\"https://www.zironmedia.com\">www.zironmedia.com</a></span></p>', 1, '2025-11-09 22:09:02', 3910.00, 3910.00, 0.00, 0.00, 0.00, 0.00, '', 1, 3, '2025-11-16', '2025-11-09', 2, 'customer', 1, 'c6a513ae4e3f5c350f0690fc59dadac5', 'Piptan Group ', 0, 234, '', '', '', 'Dubai', 'Marketing@Piptan.ae', '+971564014000', 1, 3, NULL, 36, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
