(11, 'ui/ux', '<p><a href=\"https://www.figma.com/proto/oBpLf1su1oBSe06v330d0m/Welcome-Centre?page-id=0%3A1&amp;node-id=1-2&amp;viewport=395%2C285%2C0.14&amp;t=ExWM0GcTyKeG4tCT-1&amp;scaling=scale-down&amp;content-scaling=fixed\"><span class=\"text-muted\">Live Prototype: https://www.figma.com/proto/oBpLf1su1oBSe06v330d0m/Welcome-Centre?page-id=0%3A1&amp;node-id=1-2&amp;viewport=395%2C285%2C0.14&amp;t=ExWM0GcTyKeG4tCT-1&amp;scaling=scale-down&amp;content-scaling=fixed</span></a></p>', 2, '2025-05-20 14:37:28', '2025-05-20', '2025-05-20', '2025-11-14 12:35:57', 4, 0, 5, NULL, NULL, 0, NULL, 0, 0, 0, NULL, 8, 'project', 0, 1, 0, 0, 0.00, 0, 1, 0, 1, 0),
(12, 'Design Draft of Two Flyers for Abu Dhabi English Community', '<p><strong>&#128203; Task Description:</strong><br>Design team to create <strong>two flyer drafts</strong> (one for individuals, one for corporate clients) for circulation in the <strong>English-speaking community of Abu Dhabi</strong>. Flyers should be visually attractive, well-organized, and based on the provided service content. Initial drafts must be submitted for review and confirmation before finalizing.</p>\n<p><strong>Requirements:</strong></p>\n<ul>\n<li>\n<p>Follow brand style and keep the design appealing to the English-speaking audience.</p>\n</li>\n<li>\n<p>Ensure all listed services (individual and corporate) are clearly highlighted.</p>\n</li>\n<li>\n<p>Prepare in standard print and digital formats.</p>\n</li>\n</ul>', 4, '2025-05-24 19:47:42', '2025-05-24', '2025-05-26', '2025-06-09 09:27:26', 1, 0, 5, NULL, NULL, 0, NULL, 0, 0, 0, NULL, NULL, NULL, 0, 1, 0, 0, 0.00, 0, 1, 0, 0, 0),
